function drawIsometricPrism(
  ctx: CanvasRenderingContext2D,
  x: number,
  y: number,
  width: number,
  depth: number,
  height: number,
  colors: {
    top: string;
    left: string;
    right: string;
    leftBack?: string;
    rightBack?: string;
  },
  zoom: number = 1,
) {
  const w = width * zoom * ISO_PRISM_W_FACTOR;
  const d = depth * zoom * ISO_PRISM_D_FACTOR;
  const h = height * zoom;

  // Calculate vertices for isometric box
  const topFront = { x, y: y - h + d };
  const topBack = { x, y: y - h - d };
  const topLeft = { x: x - w, y: y - h };
  const topRight = { x: x + w, y: y - h };
  const bottomFront = { x, y: y + d };
  const bottomBack = { x, y: y - d };
  const bottomLeft = { x: x - w, y };
  const bottomRight = { x: x + w, y };

  // Draw back faces first
  ctx.fillStyle = colors.leftBack || darkenColor(colors.left, -20);
  ctx.beginPath();
  ctx.moveTo(topBack.x, topBack.y);
  ctx.lineTo(topLeft.x, topLeft.y);
  ctx.lineTo(bottomLeft.x, bottomLeft.y);
  ctx.lineTo(bottomBack.x, bottomBack.y);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = "rgba(0,0,0,0.2)";
  ctx.lineWidth = zoom;
  ctx.stroke();

  ctx.fillStyle = colors.rightBack || darkenColor(colors.right, -20);
  ctx.beginPath();
  ctx.moveTo(topBack.x, topBack.y);
  ctx.lineTo(topRight.x, topRight.y);
  ctx.lineTo(bottomRight.x, bottomRight.y);
  ctx.lineTo(bottomBack.x, bottomBack.y);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = "rgba(0,0,0,0.2)";
  ctx.lineWidth = zoom;
  ctx.stroke();

  // Front-left wall
  ctx.fillStyle = colors.left;
  ctx.beginPath();
  ctx.moveTo(topLeft.x, topLeft.y);
  ctx.lineTo(topFront.x, topFront.y);
  ctx.lineTo(bottomFront.x, bottomFront.y);
  ctx.lineTo(bottomLeft.x, bottomLeft.y);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = "rgba(0,0,0,0.4)";
  ctx.lineWidth = zoom;
  ctx.stroke();

  // Front-right wall
  ctx.fillStyle = colors.right;
  ctx.beginPath();
  ctx.moveTo(topRight.x, topRight.y);
  ctx.lineTo(topFront.x, topFront.y);
  ctx.lineTo(bottomFront.x, bottomFront.y);
  ctx.lineTo(bottomRight.x, bottomRight.y);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = "rgba(0,0,0,0.3)";
  ctx.lineWidth = zoom;
  ctx.stroke();

  // Top face
  ctx.fillStyle = colors.top;
  ctx.beginPath();
  ctx.moveTo(topBack.x, topBack.y);
  ctx.lineTo(topLeft.x, topLeft.y);
  ctx.lineTo(topFront.x, topFront.y);
  ctx.lineTo(topRight.x, topRight.y);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = "rgba(0,0,0,0.2)";
  ctx.lineWidth = zoom;
  ctx.stroke();
}

function drawIsoDiamond(
  ctx: CanvasRenderingContext2D,
  cx: number,
  cy: number,
  w: number,
  d: number,
  h: number,
  topColor: string,
  leftColor: string,
  rightColor: string,
  zoom: number,
) {
  const hw = w * zoom * 0.5;
  const hd = d * zoom * 0.25;
  const hh = h * zoom;

  // Top face (diamond)
  ctx.fillStyle = topColor;
  ctx.beginPath();
  ctx.moveTo(cx, cy - hh - hd);
  ctx.lineTo(cx + hw, cy - hh);
  ctx.lineTo(cx, cy - hh + hd);
  ctx.lineTo(cx - hw, cy - hh);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = "rgba(0,0,0,0.3)";
  ctx.lineWidth = zoom;
  ctx.stroke();

  // Left face
  ctx.fillStyle = leftColor;
  ctx.beginPath();
  ctx.moveTo(cx - hw, cy - hh);
  ctx.lineTo(cx, cy - hh + hd);
  ctx.lineTo(cx, cy + hd);
  ctx.lineTo(cx - hw, cy);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = "rgba(0,0,0,0.4)";
  ctx.lineWidth = zoom;
  ctx.stroke();

  // Right face
  ctx.fillStyle = rightColor;
  ctx.beginPath();
  ctx.moveTo(cx + hw, cy - hh);
  ctx.lineTo(cx + hw, cy);
  ctx.lineTo(cx, cy + hd);
  ctx.lineTo(cx, cy - hh + hd);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = "rgba(0,0,0,0.3)";
  ctx.lineWidth = zoom;
  ctx.stroke();
}

function drawIsometricRailing(
  ctx: CanvasRenderingContext2D,
  cx: number,
  cy: number,
  rx: number,
  ry: number,
  height: number,
  segments: number,
  posts: number,
  colors: { rail: string; topRail: string; backPanel: string; frontPanel: string },
  zoom: number,
  half: "back" | "front" | "both" = "both",
) {
  const drawHalf = (isBack: boolean) => {
    const arcStart = isBack ? Math.PI : 0;
    const arcEnd = isBack ? Math.PI * 2 : Math.PI;
    const sinCheck = isBack ? (v: number) => v > 0 : (v: number) => v <= 0;
    const panelFill = isBack ? colors.backPanel : colors.frontPanel;

    ctx.strokeStyle = colors.rail;
    ctx.lineWidth = 1.5 * zoom;
    ctx.beginPath();
    ctx.ellipse(cx, cy, rx, ry, 0, arcStart, arcEnd);
    ctx.stroke();

    ctx.strokeStyle = colors.topRail;
    ctx.beginPath();
    ctx.ellipse(cx, cy - height, rx, ry, 0, arcStart, arcEnd);
    ctx.stroke();

    ctx.strokeStyle = colors.topRail;
    ctx.lineWidth = zoom;
    for (let bp = 0; bp < posts; bp++) {
      const pa = (bp / posts) * Math.PI * 2;
      if (sinCheck(Math.sin(pa))) continue;
      const px = cx + Math.cos(pa) * rx;
      const py = cy + Math.sin(pa) * ry;
      ctx.beginPath();
      ctx.moveTo(px, py);
      ctx.lineTo(px, py - height);
      ctx.stroke();
    }

    ctx.fillStyle = panelFill;
    for (let i = 0; i < segments; i++) {
      const a0 = (i / segments) * Math.PI * 2;
      const a1 = ((i + 1) / segments) * Math.PI * 2;
      if (sinCheck(Math.sin((a0 + a1) / 2))) continue;
      const x0 = cx + Math.cos(a0) * rx;
      const y0b = cy + Math.sin(a0) * ry;
      const x1 = cx + Math.cos(a1) * rx;
      const y1b = cy + Math.sin(a1) * ry;
      ctx.beginPath();
      ctx.moveTo(x0, y0b);
      ctx.lineTo(x1, y1b);
      ctx.lineTo(x1, y1b - height);
      ctx.lineTo(x0, y0b - height);
      ctx.closePath();
      ctx.fill();
    }
  };

  if (half === "back" || half === "both") drawHalf(true);
  if (half === "front" || half === "both") drawHalf(false);
}

function drawIsoCylinder(
  ctx: CanvasRenderingContext2D,
  cx: number,
  cy: number,
  rx: number,
  h: number,
  colors: { body: string; dark: string; light: string; top: string },
) {
  const ry = rx * ISO_Y_RATIO;

  ctx.fillStyle = colors.dark;
  ctx.beginPath();
  ctx.ellipse(cx, cy, rx, ry, 0, Math.PI, Math.PI * 2);
  ctx.lineTo(cx + rx, cy - h);
  ctx.ellipse(cx, cy - h, rx, ry, 0, 0, Math.PI, true);
  ctx.closePath();
  ctx.fill();

  const grad = ctx.createLinearGradient(cx - rx, 0, cx + rx, 0);
  grad.addColorStop(0, colors.dark);
  grad.addColorStop(0.35, colors.body);
  grad.addColorStop(0.7, colors.light);
  grad.addColorStop(1, colors.light);
  ctx.fillStyle = grad;
  ctx.beginPath();
  ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI);
  ctx.lineTo(cx - rx, cy - h);
  ctx.ellipse(cx, cy - h, rx, ry, 0, Math.PI, 0, true);
  ctx.closePath();
  ctx.fill();

  ctx.strokeStyle = "rgba(0,0,0,0.25)";
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(cx - rx, cy);
  ctx.lineTo(cx - rx, cy - h);
  ctx.stroke();
  ctx.beginPath();
  ctx.moveTo(cx + rx, cy);
  ctx.lineTo(cx + rx, cy - h);
  ctx.stroke();
  ctx.beginPath();
  ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI);
  ctx.stroke();

  ctx.fillStyle = colors.top;
  ctx.beginPath();
  ctx.ellipse(cx, cy - h, rx, ry, 0, 0, Math.PI * 2);
  ctx.fill();
  ctx.strokeStyle = "rgba(0,0,0,0.2)";
  ctx.stroke();
}

function drawMerlon(
  ctx: CanvasRenderingContext2D,
  cx: number,
  cy: number,
  w: number,
  d: number,
  h: number,
  colors: { top: string; left: string; right: string },
  zoom: number,
  hasArrowSlit: boolean = true,
) {
  const hw = w * zoom * 0.5;
  const hd = d * zoom * ISO_PRISM_D_FACTOR;
  const hh = h * zoom;
  const outlineStyle = "rgba(0,0,0,0.4)";
  const outlineWidth = 1 * zoom;

  // Left face
  ctx.fillStyle = colors.left;
  ctx.beginPath();
  ctx.moveTo(cx - hw, cy - hh);
  ctx.lineTo(cx, cy - hh + hd);
  ctx.lineTo(cx, cy + hd);
  ctx.lineTo(cx - hw, cy);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = outlineStyle;
  ctx.lineWidth = outlineWidth;
  ctx.stroke();

  // Right face
  ctx.fillStyle = colors.right;
  ctx.beginPath();
  ctx.moveTo(cx + hw, cy - hh);
  ctx.lineTo(cx + hw, cy);
  ctx.lineTo(cx, cy + hd);
  ctx.lineTo(cx, cy - hh + hd);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = outlineStyle;
  ctx.lineWidth = outlineWidth;
  ctx.stroke();

  // Top face
  ctx.fillStyle = colors.top;
  ctx.beginPath();
  ctx.moveTo(cx, cy - hh - hd);
  ctx.lineTo(cx + hw, cy - hh);
  ctx.lineTo(cx, cy - hh + hd);
  ctx.lineTo(cx - hw, cy - hh);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = outlineStyle;
  ctx.lineWidth = outlineWidth;
  ctx.stroke();

  // Capstone slab (wider overhang)
  const capH = 1.5 * zoom;
  const capW = (w + 1.5) * zoom * 0.5;
  const capD = (d + 1.5) * zoom * ISO_PRISM_D_FACTOR;
  const capY = cy - hh - capH;
  // Capstone top
  ctx.fillStyle = colors.top;
  ctx.beginPath();
  ctx.moveTo(cx, capY - capD);
  ctx.lineTo(cx + capW, capY);
  ctx.lineTo(cx, capY + capD);
  ctx.lineTo(cx - capW, capY);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = outlineStyle;
  ctx.lineWidth = outlineWidth;
  ctx.stroke();
  // Capstone left face
  ctx.fillStyle = colors.left;
  ctx.beginPath();
  ctx.moveTo(cx - capW, capY);
  ctx.lineTo(cx, capY + capD);
  ctx.lineTo(cx, cy - hh + hd);
  ctx.lineTo(cx - hw, cy - hh);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = outlineStyle;
  ctx.lineWidth = outlineWidth;
  ctx.stroke();
  // Capstone right face
  ctx.fillStyle = colors.right;
  ctx.beginPath();
  ctx.moveTo(cx + capW, capY);
  ctx.lineTo(cx + hw, cy - hh);
  ctx.lineTo(cx, cy - hh + hd);
  ctx.lineTo(cx, capY + capD);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = outlineStyle;
  ctx.lineWidth = outlineWidth;
  ctx.stroke();

  // Arrow slit on left face
  if (hasArrowSlit) {
    const slitCx = cx - hw * 0.5;
    const slitCy = cy - hh * 0.5 + hd * 0.25;
    ctx.fillStyle = "rgba(10,10,15,0.6)";
    ctx.beginPath();
    ctx.moveTo(slitCx, slitCy - 2.2 * zoom);
    ctx.lineTo(slitCx + 0.6 * zoom, slitCy);
    ctx.lineTo(slitCx, slitCy + 2.2 * zoom);
    ctx.lineTo(slitCx - 0.6 * zoom, slitCy);
    ctx.closePath();
    ctx.fill();
  }
}

/**
 * Draws a 3D isometric gothic (pointed-arch) window flush against an iso wall face.
 * @param face "left" or "right" — determines the iso skew direction
 * @param glowColor CSS color string for the inner glow, or null for no glow
 * @param glowAlpha opacity multiplier for the glow
 * @param colors optional overrides for frame, void, and sill
 */
function drawIsoGothicWindow(
  ctx: CanvasRenderingContext2D,
  cx: number,
  cy: number,
  w: number,
  h: number,
  face: "left" | "right",
  zoom: number,
  glowColor: string | null = "rgba(255, 150, 50",
  glowAlpha: number = 0.3,
  colors?: { frame?: string; void?: string; sill?: string },
) {
  const slope = face === "right" ? -ISO_Y_RATIO : ISO_Y_RATIO;
  const hw = w * zoom * 0.5;
  const hh = h * zoom * 0.5;
  const archPeak = hh + 2.5 * zoom;

  // Recess depth for 3D effect
  const rd = 1.2 * zoom;
  const rdx = face === "right" ? rd : -rd;
  const rdy = -rd * ISO_Y_RATIO;

  const frameColor = colors?.frame ?? "#2a2a32";
  const voidColor = colors?.void ?? "#1a1a22";
  const sillColor = colors?.sill ?? "#5a5a62";

  // Frame recess (darker border)
  ctx.fillStyle = frameColor;
  ctx.beginPath();
  ctx.moveTo(cx - hw + rdx, cy - hh + -hw * slope + rdy);
  ctx.lineTo(cx + rdx, cy - archPeak + rdy);
  ctx.lineTo(cx + hw + rdx, cy - hh + hw * slope + rdy);
  ctx.lineTo(cx + hw + rdx, cy + hh + hw * slope + rdy);
  ctx.lineTo(cx - hw + rdx, cy + hh + -hw * slope + rdy);
  ctx.closePath();
  ctx.fill();

  // Window void (darkest)
  ctx.fillStyle = voidColor;
  ctx.beginPath();
  ctx.moveTo(cx - hw, cy - hh + -hw * slope);
  ctx.lineTo(cx, cy - archPeak);
  ctx.lineTo(cx + hw, cy - hh + hw * slope);
  ctx.lineTo(cx + hw, cy + hh + hw * slope);
  ctx.lineTo(cx - hw, cy + hh + -hw * slope);
  ctx.closePath();
  ctx.fill();

  // Outline
  ctx.strokeStyle = "rgba(0,0,0,0.4)";
  ctx.lineWidth = 0.8 * zoom;
  ctx.stroke();

  // Inner glow
  if (glowColor) {
    ctx.fillStyle = `${glowColor}, ${glowAlpha})`;
    ctx.beginPath();
    const inset = 0.3 * zoom;
    ctx.moveTo(cx - hw + inset, cy - hh + -hw * slope + inset * ISO_Y_RATIO);
    ctx.lineTo(cx, cy - archPeak + inset);
    ctx.lineTo(cx + hw - inset, cy - hh + hw * slope + inset * ISO_Y_RATIO);
    ctx.lineTo(cx + hw - inset, cy + hh + hw * slope - inset * ISO_Y_RATIO);
    ctx.lineTo(cx - hw + inset, cy + hh + -hw * slope - inset * ISO_Y_RATIO);
    ctx.closePath();
    ctx.fill();
  }

  // Stone sill at bottom
  ctx.fillStyle = sillColor;
  ctx.beginPath();
  const sillH = 1 * zoom;
  ctx.moveTo(cx - hw - 0.5 * zoom, cy + hh + -hw * slope);
  ctx.lineTo(cx + hw + 0.5 * zoom, cy + hh + hw * slope);
  ctx.lineTo(cx + hw + 0.5 * zoom, cy + hh + hw * slope + sillH);
  ctx.lineTo(cx - hw - 0.5 * zoom, cy + hh + -hw * slope + sillH);
  ctx.closePath();
  ctx.fill();
}

